// Define the discovery rounds for this execution.
// Each round fetches a different genre/region combination.
return [
  { json: { action: 'genre', genre: 'afrobeats',      region: 'NG', limit: 3, label: 'Afrobeats Nigeria' } },
  { json: { action: 'genre', genre: 'makossa',         region: 'CM', limit: 2, label: 'Makossa Cameroon' } },
  { json: { action: 'genre', genre: 'african_hiphop',  region: 'ZA', limit: 2, label: 'African Hip-Hop' } },
  { json: { action: 'genre', genre: 'african_rb',      region: 'NG', limit: 2, label: 'African R&B' } },
  { json: { action: 'genre', genre: 'global_collabs',  region: 'US', limit: 2, label: 'Global Collabs' } },
  { json: { action: 'trending', genre: 'afropop',      region: 'GH', limit: 2, label: 'Trending Ghana' } }
];

// Flatten all video arrays from discovery rounds into individual items.
// Each item becomes one article draft.
const result = $input.first().json;
if (!result.videos || result.videos.length === 0) return [];
const label = $('Define Discovery Rounds').item.json.label || 'African Music';
return result.videos.map(v => ({
  json: {
    videoId:      v.id,
    title:        v.title,
    channel:      v.channelTitle,
    description:  v.description,
    thumbnail:    v.thumbnail,
    watchUrl:     v.watchUrl,
    embedUrl:     v.embedUrl,
    viewCount:    v.viewCount,
    duration:     v.duration,
    publishedAt:  v.publishedAt,
    genre_label:  label,
    isLive:       v.isLive,
  }
}));

const item = $input.first();
const video = $('Split Video Items').item.json;
try {
  const ai = JSON.parse(item.json.text || '{}');
  if (!ai.title || !ai.body) throw new Error('Missing title or body');
  // Inject video ID for dedup tracking
  const body = ai.body.replace('</p>\n', '</p>\n<!-- yt:' + video.videoId + ' -->\n', 1) || ai.body;
  return [{ json: {
    valid:         true,
    title:         ai.title,
    excerpt:       ai.excerpt || '',
    body:          ai.body,
    category_slug: ai.category_slug || 'music',
    meta_title:    ai.meta_title   || ai.title.slice(0,60),
    meta_desc:     ai.meta_desc    || ai.excerpt?.slice(0,160) || '',
    featured_image: video.thumbnail,
    source_url:    video.watchUrl,
    language:      'en',
  }}];
} catch(e) {
  return [{ json: { valid: false, error: e.message, video_id: video.videoId } }];
}
